import 'package:flutter_fractals/core/modules/base_classes/cellular_module_base.dart';

/// Shared public behavior checks for generated reaction-diffusion modules.
///
/// Owns smoke-test assertions common to this test family. It exposes one
/// contract function and must not know about individual generated module
/// classes, shaders, UI, or app orchestration.
void expectReactionDiffusionModuleContract({
  required CellularModule module,
  required String expectedId,
  required String expectedShader,
}) {
  test('${module.runtimeType} instantiates', () {
    expect(module.id, expectedId);
    expect(module.shader, expectedShader);
  });

  test('${module.runtimeType} presets are well-formed', () {
    expect(module.presets, isNotEmpty);
    for (final p in module.presets) {
      final preset = p as dynamic;
      expect(preset.id, isNotEmpty);
      expect(preset.name, isNotEmpty);
    }
  });

  test('${module.runtimeType} metadata is consistent', () {
    final metadata = module.metadata as dynamic;
    expect(metadata.id, module.id);
  });
}

